const input = items[0]?.json || {};

return [{
  json: {
    ...input,
    config: {
      plataformaImportUrl: 'http://localhost:3000/api/comercial/hotmart/import',
      plataformaTenantId: 'ff24d2bc-22e2-4a5b-bc8c-f6d25a7fa3b0',
      n8nIngestToken: 'COLE_AQUI_O_MESMO_N8N_INGEST_TOKEN'
    }
  }
}];

function get(obj, path) {
  return path.split('.').reduce((acc, key) => {
    if (!acc || typeof acc !== 'object') return undefined;
    return acc[key];
  }, obj);
}

function first(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }
  return null;
}

function text(...values) {
  const value = first(...values);
  return value === null ? null : String(value).trim();
}

function number(...values) {
  const value = first(...values);
  if (value === null) return null;
  if (typeof value === 'number') return Number.isFinite(value) ? value : null;
  const normalized = String(value).replace(/\./g, '').replace(',', '.');
  const parsed = Number(normalized);
  return Number.isFinite(parsed) ? parsed : null;
}

function integer(...values) {
  const value = number(...values);
  return value ? Math.max(1, Math.round(value)) : 1;
}

function date(...values) {
  const value = first(...values);
  if (value === null) return null;
  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed.toISOString();
}

function hotmartStatus(payload) {
  return text(
    get(payload, 'data.purchase.status'),
    get(payload, 'purchase.status'),
    get(payload, 'data.status'),
    payload.status,
    payload.event
  ) || 'unknown';
}

const input = items[0]?.json || {};
const config = input.config || {};
const body = input.body || input;
const data = body.data || body;
const purchase = data.purchase || body.purchase || {};
const buyer = data.buyer || purchase.buyer || body.buyer || {};
const product = data.product || purchase.product || body.product || {};
const payment = data.payment || purchase.payment || body.payment || {};
const price = purchase.price || data.price || body.price || {};
const commissions = Array.isArray(data.commissions) ? data.commissions : Array.isArray(body.commissions) ? body.commissions : [];
const producerCommission = commissions.find((commission) => String(commission.source || '').toUpperCase().includes('PRODUCER')) || commissions[0] || {};

const transactionId = text(
  purchase.transaction,
  data.transaction,
  body.transaction,
  body.transaction_id,
  body.id,
  `${body.event || 'hotmart'}-${Date.now()}`
);

const row = {
  event_id: text(body.id, body.event_id, get(body, 'event.id'), `${body.event || 'hotmart'}-${transactionId}`),
  transaction_id: transactionId,
  event: text(body.event, body.event_name, body.type),
  product_id: text(product.id, product.ucode, body.product_id, body.hotmart_product_id),
  product_name: text(product.name, product.title, body.product_name, body.produto_nome),
  buyer_email: text(buyer.email, body.buyer_email, body.email)?.toLowerCase(),
  buyer_name: text(buyer.name, buyer.full_name, body.buyer_name, body.name),
  buyer_phone: text(buyer.phone, buyer.phone_number, body.buyer_phone, body.telefone),
  status: hotmartStatus(body),
  payment_type: text(payment.type, payment.method, purchase.payment_type, body.payment_type),
  installments: integer(payment.installments_number, payment.installments, purchase.installments_number, body.installments, body.parcelas),
  currency: text(price.currency_code, price.currency, body.currency, body.moeda) || 'BRL',
  gross_amount: number(price.value, purchase.price?.value, data.price?.value, body.gross_amount, body.valor_bruto, body.price),
  net_amount: number(producerCommission.value, data.commission?.value, body.net_amount, body.valor_liquido),
  fees: number(data.fees?.value, purchase.fees?.value, body.fees, body.taxas),
  purchase_date: date(purchase.order_date, purchase.purchase_date, body.purchase_date, body.data_compra, data.creation_date),
  approved_date: date(purchase.approved_date, body.approved_date, body.data_aprovacao),
  refund_date: date(purchase.refund_date, body.refund_date, body.data_reembolso),
  chargeback_date: date(purchase.chargeback_date, body.chargeback_date, body.data_chargeback),
  expected_payment_date: date(data.receivable?.expected_payment_date, data.payment?.expected_payment_date, body.expected_payment_date, body.data_prevista),
  source_sck: text(data.tracking?.source_sck, purchase.tracking?.source_sck, body.source_sck, body.sck),
  raw_payload: body
};

if (!row.transaction_id || !row.buyer_email) {
  return [{ json: { config, rows: [], skipped: true, reason: 'Evento Hotmart sem transaction_id ou buyer_email.', raw_payload: body } }];
}

return [{ json: { config, tenant_id: config.plataformaTenantId, rows: [row], count: 1 } }];
